const OPENAI_API_KEY = "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";

// 🔥 BLOG GENERATION (IMPROVED)
export async function generateBlog(title) {
  try {
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [
          {
            role: "system",
            content:
              "You are a professional blog writer who writes detailed and engaging articles.",
          },
          {
            role: "user",
            content: `
Write a detailed blog post about "${title}".

Requirements:
- 300–500 words
- Use proper paragraphs (not one line)
- Add introduction
- Add main points with explanation
- Add conclusion
- Make it engaging and human-like
`,
          },
        ],
        max_tokens: 700,
        temperature: 0.9,
      }),
    });

    const data = await res.json();

    return data?.choices?.[0]?.message?.content || "No content generated.";
  } catch (err) {
    console.error(err);
    return `This is a fallback article about ${title}.`;
  }
}
